const output = $input.first().json.text || $input.first().json.content || '';
const posts = [];
const matches = output.match(/\[POST \d+\]\n([\s\S]*?)(?=\n\[POST \d+\]|$)/g);

if (matches) {
  for (const match of matches) {
    const tekst = match.replace(/\[POST \d+\]\n/, '').trim();
    if (tekst.length > 50) {
      posts.push({ tekst });
    }
  }
}

return posts.map(p => ({ json: p }));
